<template>
  <div>
    <el-card>
      <div style="width: 70%">
        <el-form v-loading="loading" label-width="180px" :model="form">
          <el-form-item label="小程序AppId">
            <el-input v-model="form.authorizer_appid" type="text" />
          </el-form-item>
          <el-form-item label="應用私鑰">
            <el-input v-model="form.merchant_private_key" type="textarea" :rows="5" />
          </el-form-item>
          <el-form-item label="api加密類型">
            <div>
              <el-radio v-model="form.api_sign_method" label="key"> 密鑰 </el-radio>
              <!-- <el-radio
                v-model="form.api_sign_method"
                label="cert"
              >
                證書
              </el-radio> -->
            </div>
          </el-form-item>
          <el-form-item v-if="form.api_sign_method === 'cert'" label="支付寶公鑰證書文件">
            <el-input v-model="form.alipay_cert_path" type="textarea" :rows="5" />
          </el-form-item>
          <el-form-item v-if="form.api_sign_method === 'cert'" label="支付寶根證書文件">
            <el-input v-model="form.alipay_root_cert_path" type="textarea" :rows="5" />
          </el-form-item>
          <el-form-item v-if="form.api_sign_method === 'cert'" label="應用公鑰證書文件">
            <el-input v-model="form.merchant_cert_path" type="textarea" :rows="5" />
          </el-form-item>
          <el-form-item v-if="form.api_sign_method === 'key'" label="支付寶公鑰字符串">
            <el-input v-model="form.alipay_public_key" type="textarea" :rows="5" />
          </el-form-item>
          <!-- <el-form-item label="支付類異步通知地址">
            <el-input
              v-model="form.notify_url"
              type="text"
            />
          </el-form-item> -->
          <el-form-item label="AES密鑰">
            <el-input v-model="form.encrypt_key" type="text" />
          </el-form-item>

          <el-form-item size="large">
            <el-button>取消</el-button>
            <el-button type="primary" @click="save"> 儲存 </el-button>
          </el-form-item>
        </el-form>
      </div>
    </el-card>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import { getAliMiniAppSetting, saveAliMiniAppSetting } from '../../../api/aliminiapp'

export default {
  components: {},

  data() {
    return {
      loading: false,
      form: {
        authorizer_appid: '',
        merchant_private_key: '',
        api_sign_method: 'key',
        alipay_cert_path: '',
        alipay_root_cert_path: '',
        merchant_cert_path: '',
        alipay_public_key: '',
        notify_url: '',
        encrypt_key: ''
      }
    }
  },
  mounted() {
    this.getInfo()
  },
  methods: {
    // 獲取訊息
    getInfo() {
      this.loading = true
      getAliMiniAppSetting(this.params).then((res) => {
        this.form = res.data.data
        this.loading = false
      })
    },
    // 儲存數據
    save() {
      saveAliMiniAppSetting(this.form).then((res) => {
        this.$message({ type: 'success', message: '操作成功' })
        this.getInfo()
      })
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  }
}
</script>
